```php
<?php
function getVilles() {
    // Paramètres de connexion à la base de données
    $host = '127.0.0.1';
    $dbname = 'nom_de_votre_base_de_donnees';
    $username = 'root';
    $password = ''; // Remplacez par votre mot de passe (s'il y en a un)
    $port = '3306';

    try {
        // Création d'une nouvelle instance PDO
        $pdo = new PDO("mysql:host=$host;port=$port;dbname=$dbname;charset=utf8", $username, $password);

        // Définition du mode d'erreur à Exception
        $pdo->setAttribute(PDO::ATTR_ERRMODE, PDO::ERRMODE_EXCEPTION);

        // Préparation de la requête
        $stmt = $pdo->prepare("SELECT * FROM Villes");

        // Exécution de la requête
        $stmt->execute();

        // Récupération des résultats
        $villes = $stmt->fetchAll(PDO::FETCH_ASSOC);

        // Retourne les villes récupérées
        return $villes;

    } catch(PDOException $e) {
        // Gestion des erreurs
        die("Erreur de connexion à la base de données: " . $e->getMessage());
    }
}

// Utilisation de la fonction
$villes = getVilles();
echo '<pre>'; print_r($villes); echo '</pre>'; // Affichage des résultats
?>
```

Remplacez `'nom_de_votre_base_de_donnees'` par le nom réel de votre base de données.

