```php
function register($url, $ville, $metier) {
    $emails = get_prospects($url); // Supposons que cette fonction renvoie un tableau d'emails
    $pdo = db(); // Établit la connexion à la base de données

    // Préparation de la requête SQL pour insérer les données
    $sql = "INSERT INTO Contacts (email, villeId, metierId, status) VALUES (:email, :villeId, :metierId, 'suspect')";

    // Prépare la déclaration pour l'exécution
    $stmt = $pdo->prepare($sql);

    // Commence une transaction pour améliorer la performance en cas de multiples insertions
    $pdo->beginTransaction();

    try {
        // Récupère les ID des villes et métiers à partir de leurs noms. Cela suppose que ces noms sont uniques.
        $villeId = $pdo->query("SELECT id FROM Villes WHERE nom = '{$ville}'")->fetchColumn();
        $metierId = $pdo->query("SELECT id FROM Métiers WHERE nom = '{$metier}'")->fetchColumn();

        // Exécute une requête d'insertion pour chaque email
        foreach ($emails as $email) {
            // Lie les paramètres à la déclaration préparée
            $stmt->bindParam(':email', $email);
            $stmt->bindParam(':villeId', $villeId);
            $stmt->bindParam(':metierId', $metierId);

            // Exécute la requête
            $stmt->execute();
        }

        // Commit la transaction
        $pdo->commit();
    } catch (Exception $e) {
        // Annule la transaction en cas d'erreur
        $pdo->rollBack();
        throw $e; // Lève l'exception pour la gérer à l'extérieur de la fonction
    }
}
```

